export function getVerseOfTheDay(): Verse {
  const day = Math.floor(Date.now() / (1000 * 60 * 60 * 24));
  return VERSES[day % VERSES.length];
}

export function getVerseForIndex(index: number): Verse {
  const i = ((index % VERSES.length) + VERSES.length) % VERSES.length;
  return VERSES[i];
}
